def en_uzun_k_farkli(sayilar, k):
    if k <= 0:
        return 0
    sayim = {}
    sol = 0
    en_uzun = 0
    for sag in range(len(sayilar)):
        sayim[sayilar[sag]] = sayim.get(sayilar[sag], 0) + 1
        while len(sayim) > k:
            sayim[sayilar[sol]] -= 1
            if sayim[sayilar[sol]] == 0:
                del sayim[sayilar[sol]]
            sol += 1
        en_uzun = max(en_uzun, sag - sol + 1)
    return en_uzun
